const https = require('https');
const http = require('http');
const { URL } = require('url');
const { parse } = require('node-html-parser');

const fetchMetadata = async (userUrl) => {
  try {
    // Validate URL
    const url = new URL(userUrl);
    if (!['http:', 'https:'].includes(url.protocol)) {
      throw new Error('Invalid URL protocol');
    }

    // Block internal IP addresses
    const internalIpRegex = /^(?:10|127|169\.254|192\.168|172\.(?:1[6-9]|2\d|3[01]))\./;
    if (internalIpRegex.test(url.hostname)) {
      throw new Error('Internal IP addresses are not allowed');
    }

    // Fetch the page
    const fetch = url.protocol === 'https:' ? https : http;
    return new Promise((resolve, reject) => {
      fetch.get(url, (res) => {
        if (res.statusCode !== 200) {
          reject(new Error(`Request Failed. Status Code: ${res.statusCode}`));
          return;
        }

        let rawData = '';
        res.on('data', (chunk) => { rawData += chunk; });
        res.on('end', () => {
          try {
            const root = parse(rawData);
            const metadata = {
              title: root.querySelector('title')?.text || '',
              description: root.querySelector('meta[name="description"]')?.getAttribute('content') || '',
              ogTitle: root.querySelector('meta[property="og:title"]')?.getAttribute('content') || '',
              ogDescription: root.querySelector('meta[property="og:description"]')?.getAttribute('content') || '',
              ogImage: root.querySelector('meta[property="og:image"]')?.getAttribute('content') || ''
            };
            resolve(metadata);
          } catch (e) {
            reject(e);
          }
        });
      }).on('error', (e) => {
        reject(e);
      });
    });
  } catch (error) {
    throw new Error(`Failed to fetch metadata: ${error.message}`);
  }
};

exports.fetchMetadata = fetchMetadata;